import Vue from 'vue'
import VueRouter from 'vue-router'
import Home from '../views/Home.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home
  },
  {
    path: '/login',
    name: 'login',
    component: function () {
      return import( '../views/Login.vue')
    }
  },
  {
    path: '/xiang',
    name: 'xiang',
    component: function () {
      return import( '../components/xiang.vue')
    }
  },
  {
    path: '/qiang',
    name: 'qiang',
    component: function () {
      return import('../views/Qing.vue')
    },
    children:[
      {
        path:'a',
        name: 'a',
        component: function () {
          return import('@/components/a.vue')
        },
      },
      {
        path:'b',
        name: 'b',
        component: function () {
          return import('@/components/b.vue')
        },
      },
      {
        path:'c',
        name: 'c',
        component: function () {
          return import('@/components/c.vue')
        },
      },
      {
        path:'d',
        name: 'd',
        component: function () {
          return import('@/components/d.vue')
        },
      },
      {
        path:'/qiang',
        redirect: '/qiang/a'
      }
    ]
  },
]

const router = new VueRouter({
  routes
})

export default router
