import http from './http'
// get请求方式
export function gets(url,data){
   return http.get(url,{
      params:data
   })
}
// post请求方式
export function posts(url,data){
   return http.post(url,data)
}

// get请求城市的接口
export function ajaxcity(type){
   return gets(`/v1/cities?type=${type}`)
}

