import axios from 'axios';

let instance =axios.create({
   baseURL:'http://elm.cangdu.org',
   timeout:3000
})

// 请求拦截器
instance.interceptors.request.use(config=>{
   // console.log(config)
      return config
})

instance.interceptors.response.use(res=>{
   // console.log(res)
   return res
})
export default instance;