<template>
  <div class="home">

    <hea id="zqd">
      <div slot="left">elm-me</div>
      <div slot="center">
        <button v-show="flag" @click="jump('zd')" class="btn">置顶</button>
      </div>
      <div slot="right">
        <van-icon name="manager" @click="go()" v-show="pan"/>
        <span v-show="!pan" @click="tiao()">登录|注册</span>
      </div>


    </hea>


    <div class="ding">
      {{ding.name}}
    </div>
    <p>热门城市</p>
    <div  class="zqd">
      <p v-for="(item,index) in arr">
        <!-- <a :href="'#'+item">{{item}}</a> -->
        <span :ref="'#'+item" @click="jump(item)">{{item}}</span>
      </p>
        <!-- <van-index-bar>
          <van-index-anchor :index="item" v-for="(item,index) in arr"/>
        </van-index-bar> -->
    </div>

    <ul class="hot">
      <li v-for="(item,index) in remen" :key="index">
        {{item.name}}
      </li>
    </ul>
    <div v-for="(item,index) in arr">
      <p :id="item" :ref="item" class="pp">{{item}}</p>
        <ul class="hot">
          <li v-for="(k,i) in list[item]" @click="ass(k.id)">
            {{k.name}}
          </li>
        </ul>

    </div>
    <!-- home -->
  </div>
</template>

<script>
// @ is an alias to /src
// import HelloWorld from '@/components/HelloWorld.vue'
import {ajaxcity} from '../utils/api'
import hea from '../components/header.vue'

export default {
  name: 'Home',
  data () {
    return {
      ding:{},//定位城市
      remen:[],//热门城市
      list:[],
      arr:[],//字母
      flag:false,
      pan:false
    }
  },
  mounted () {
    this.ajax()
    　// 滚动条的获取
    　　window.addEventListener('scroll', this.handleScrollx, true)
    let a=sessionStorage.getItem('token')
    if(a){
      this.pan=true
    }else{
      this.pan=false
    }
  },
  methods: {
    async ajax(){
      // 调用请求当前城市的方法，在utils下面封装好的，直接传参数就可以
      let {data} = await ajaxcity('guess')
      // console.log(data.name)
      this.ding=data
      // 调用请求城市的方法，在utils下面封装好的，直接传参数就可以
      let {data:res} = await ajaxcity('hot')
      // console.log(res)
      this.remen=res

      let {data:group} = await ajaxcity('group')
      // console.log(group)
      this.arr=Object.keys(group).sort()
      // console.log(this.arr)
      this.list=group
    },
    jump(z){
      if(z=='zd'){
        document.body.scrollTop = document.documentElement.scrollTop =0
      }else{
        console.log(this.$refs[z][0].offsetTop)
       document.body.scrollTop = document.documentElement.scrollTop = this.$refs[z][0].offsetTop-50;
      }

    },
    handleScrollx() {
          // console.log('滚动高度', window.pageYOffset)
          // console.log('距离顶部高度', this.$refs.obtain.getBoundingClientRect().top)
          if(window.pageYOffset>50){
            this.flag=true
          }else{
            this.flag=false
          }
        },
       async  ass(i){
          // console.log(i)
          let {data} = await this.$http.get(`http://elm.cangdu.org/v1/cities/${i}`)
          // console.log(data)
          sessionStorage.setItem('a',JSON.stringify(data.name))
          this.$router.push({
            path:'/xiang',
            query:{
              data
            }
          })
        },
        tiao(){
          this.$router.push('/login')
        },
        go(){
          this.$router.push('/qiang/d')
        }
  },
  components: {
    hea
  }
}
</script>
